import{_ as n,o as t,c as i,ag as r}from"./chunks/framework.DXGyWiRo.js";const a="/images/lekt2501.jpg",o="/images/lekt2502.jpg",s="/images/lekt2503.jpg",u="/images/lekt2504.jpg",p="/images/lekt2505.jpg",l="/images/lekt2506.jpg",d="/images/lekt2507.jpg",v=JSON.parse('{"title":"Lektion 25","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion25.md","filePath":"lektionen/lektion25.md"}'),b={name:"lektionen/lektion25.md"};function h(m,e,c,g,k,q){return t(),i("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-25" tabindex="-1">Lektion 25 <a class="header-anchor" href="#lektion-25" aria-label="Permalink to &quot;Lektion 25&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>25.1. Bildung des Ablativ (पञ्चमी = &quot;fünfte Kasusendung&quot;)</li><li>25.2. Gebrauch des Ablativ (पञ्चमी)</li><li>25.3. Das Suffix -तस्</li><li>25.4. Andere Möglichkeiten, Begründungen auszudrücken</li><li>25.5. Wortliste</li><li>25.6. Übung</li><li>25.7. सुभाषितानि</li><li>25.8. Übersetzungsübung</li></ul><h2 id="_25-1-bildung-des-ablativ-पञ्चमी-funfte-kasusendung" tabindex="-1">25.1. Bildung des Ablativ (पञ्चमी = &quot;fünfte Kasusendung&quot;) <a class="header-anchor" href="#_25-1-bildung-des-ablativ-पञ्चमी-funfte-kasusendung" aria-label="Permalink to &quot;25.1. Bildung des Ablativ (पञ्चमी = &quot;fünfte Kasusendung&quot;)&quot;">​</a></h2><p>Außer bei Maskulina / Neutra auf -a sowie den Pronomina sind im Singular in allen Deklinationsklassen die Formen des Ablativ (पञ्चमी) mit denen des Genetiv (षष्ठी) identisch.</p><p>Außer bei den Personalpronomina sind in allen Deklinationen im Plural die Formen des Ablativ mit denen des Dativ (चतुर्थी) identisch.</p><p>Jetzt erkennen Sie den Grund für die Reihenfolge der Kasus (विभक्ति) im Sanskrit: sie sind so angeordnet, dass gleichlautende Formen möglichst beieinander - bzw. untereinander - stehen.</p><p>Ablativ Singular der Maskulina / Neutra auf -a</p><p>दव Abl. sg. देवात्</p><p>Frage-, Relativ- und Demonstrativpronomina:</p><p>|   | Ablativ Singular<br> Maskulinum / Neutrum | Ablativ Singular<br> Femininum | | --- | --- | --- | | किम्</p><p>|</p><p>कस्मात्</p><p>|</p><p>कस्यास्</p><p>| | यद् | यस्मात् | यस्यास् | | तद् | तस्मात् | तस्यास् | | एतद् | एतस्मात् | एतस्यास् | | इदम् | अस्मात् | अस्यास् |</p><h2 id="_25-2-gebrauch-des-ablativ-पञ्चमी" tabindex="-1">25.2. Gebrauch des Ablativ (पञ्चमी) <a class="header-anchor" href="#_25-2-gebrauch-des-ablativ-पञ्चमी" aria-label="Permalink to &quot;25.2. Gebrauch des Ablativ (पञ्चमी)&quot;">​</a></h2><p>&quot;Der Ablativ bezeichnet dasjenige, das fest bleibt, wenn etwas davon weggeht.&quot;</p><p>Pāṇini 2,3,28 + 1,4,24</p><p>Der Ablativ steht vor allem auf die Fragen &quot;Woher?&quot;, &quot;Warum?&quot;.</p><p>1. Der Ablativ bezeichnet also den Ausgangspunkt, die Herkunft und den Stoff:</p><p>Beispiele:</p><blockquote><p>ग्रमादागच्छति = &quot;Er kommt aus dem Dorf&quot;</p><p>अश्वात्पतितः = &quot;vom Pferde gefallen&quot;</p><p>तेभ्यो लब्धम् = &quot;von ihnen (her) empfangen&quot;</p></blockquote><p>Der Ablativ kann daher auch die Person bezeichnen, von der man etwas kauft, hört, wünscht usw.</p><p>Beispiele:</p><blockquote><p>गुरोर्धर्मं शृणोति = &quot;er hört vom Lehrer über den Dharma&quot;</p><p>ब्राह्मणः क्षत्रियाद्धेनुमिच्छति = &quot;der Brahmane wünscht sich vom Kṣatriya eine Milchkuh&quot;</p></blockquote><p>2. Der Ablativ steht bei Verben mit den Bedeutungen &quot;abhalten von&quot;, &quot;schützen vor&quot;, &quot;verteidigen gegen&quot;, &quot;sich fürchten vor&quot;:</p><p>Beispiel:</p><blockquote><p>अरिभ्यो रक्षति = &quot;er schützt vor den Feinden&quot;</p></blockquote><p>3. Der Ablativ bezeichnet den Grund oder die Ursache:</p><p>Beispiele:</p><blockquote><p>क्रोधात्पुत्रं हन्ति = &quot;Er erschlägt seinen Sohn aus Zorn&quot;</p><p>कृतपापत्वान्नरकं गच्छति = &quot;Weil er Böses getan hat, kommt er in die Hölle&quot; (« Weil er einer ist, durch den Böses getan wurde)</p><p>पापकरणान्नरकं गच्छति = &quot;Weil er Böses tut / tat, kommt er in die Hölle&quot;</p></blockquote><p>Nomina, die nicht Feminina sind, können, um den Grund einer Tätigkeit zu bezeichnen, im Instrumentalis (तृतीया) oder Ablativ (पञ्जमी) stehen. Feminina stehen in diesem Sinn in der Regel im Instrumentalis, können aber gelegentlich auch im Ablativ stehen.</p><h2 id="_25-3-das-suffix-तस्" tabindex="-1">25.3. Das Suffix -तस् <a class="header-anchor" href="#_25-3-das-suffix-तस्" aria-label="Permalink to &quot;25.3. Das Suffix -तस्&quot;">​</a></h2><p>Will man im Singular (eindeutig) ausdrücken, dass das Wort in ablativischer Bedeutung verwendet wird, kann man an den Wortstamm das Suffix -तस् anhängen, das Adverbien mit meist ablativischer Bedeutung bildet (auf die Frage &quot;Woher?&quot;):</p><p>Beispiele:</p><blockquote><p>आदितस् = &quot;von Anfang an&quot;</p><p>धर्मतस् = &quot;wegen des Dharma, aufgrund des Dharma&quot;</p></blockquote><p>Das Suffix -तस् tritt auch an Pronominalstämme:</p><blockquote><p>तद् : ततस् (« ta-tas) &quot;von dort, dort, dorthin, darauf, dann, darum&quot;</p><p>यद् : यतस् &quot;von welchem, wovon, woher, wo, wohin, weshalb, weil&quot; (relativ)</p><p>किम् :  कुतस् &quot;woher?&quot; &quot;warum?&quot;</p></blockquote><h2 id="_25-4-andere-moglichkeiten-begrundungen-auszudrucken" tabindex="-1">25.4. Andere Möglichkeiten, Begründungen auszudrücken <a class="header-anchor" href="#_25-4-andere-moglichkeiten-begrundungen-auszudrucken" aria-label="Permalink to &quot;25.4. Andere Möglichkeiten, Begründungen auszudrücken&quot;">​</a></h2><p>1. Relativsätze</p><p>1. Relativsätze drücken oft eine kausale (begründende), konsekutive (folgernde) oder finale (bezweckende) Beziehung zum Hauptsatz aus.</p><p>Formen des Relativpronomens, die als kausale Konjunktion dienen:</p><ul><li>ablativisch: <ul><li>यतस् ... Nebensatz ... ततस् ... Hauptsatz ... = &quot;weil ..., deshalb ...&quot;</li><li>यस्मात् ... Nebensatz ... तस्मात् ... Hauptsatz ... = &quot;weil ..., deshalb ...&quot;</li></ul></li><li>instrumental: <ul><li>येन ... Nebensatz ... तेन ... Hauptsatz ... = &quot;wodurch/weil ..., dadurch / deswegen ...&quot;</li></ul></li></ul><p>Beispiel:</p><blockquote><p>यतो (यस्माद् / येन) धममिच्छति [ततो (तस्माद् / तेन)] रामो व्रतं चरति = &quot;Weil Rāma Wohlstand wünscht, praktiziert er das Gelübde&quot;</p></blockquote><p>2. हि</p><p>Hauptsätze kann man mittels der Partikel हि &quot;denn, weil&quot; miteinander verknüpfen. Ein Satz mit हि (das nicht an erster Stelle stehen darf, sondern in Prosa an zweiter Stelle stehen muss) gibt eine Begründung an entweder für den vorhergehenden Satz oder für den darauffolgenden Satz:</p><p>Beispiel:</p><blockquote><p>जनाः पुण्यं कुर्वन्ति । स्वर्गं हि गन्तुमिच्छन्ति = &quot;Die Leute tun Verdienstliches. Sie wollen nämlich in den Himmel kommen.&quot;</p></blockquote><p>3. Instrumentalis (तृतीया)</p><p>3.  Neben dem Ablativ (पञ्चमी) wird der Instrumentalis (तृतीया) zur Angabe des Grundes oder der Ursache verwendet. Bei femininen Nomina ist der Instrumentalis im Allgemeinen obligatorisch.</p><p>Beispiel:</p><blockquote><p>क्रोधेन पुत्रं हन्ति = &quot;Er erschlägt seinen Sohn aus Zorn&quot; = &quot;Er erschlägt seinen Sohn im Zorn&quot;</p></blockquote><p>4. Nomina</p><p>4. Daneben kann man selbstverständlich Begründungen auch ausdrücken durch Konstruktionen mit</p><ul><li>कारण n. &quot;Ursache&quot;: कारणात् । कारणेन</li><li>हेतु m.</li><li>andere Nomina in der Bedeutung &quot;Ursache&quot;</li></ul><p>+ Genetiv (षष्ठी) oder als Hinterglied von Komposita:</p><p>Beispiel:</p><blockquote><p>पुण्यस्य कारणात् (हेतोः u.s.w.) = &quot;wegen des Verdienstes&quot;</p></blockquote><p>5. इति</p><p>5. Das Motiv für eine Tätigkeit kann man als Gedanken mit इति angeben:</p><p>Beispiel:</p><blockquote><p>सत्यसंबुद्धः सुगत इत्यानन्दो गौतमं धर्मं पृच्छति  = &quot;Weil der Sugata vollkommen zur Wahrheit erwacht ist, fragt Ānanda den Gautama nach seiner Lehre&quot; (« &quot;Denkend &quot;Der Sugata ist vollkommen zur Wahrheit erwacht&quot; ...)</p></blockquote><h2 id="_25-5-wortliste" tabindex="-1">25.5. Wortliste <a class="header-anchor" href="#_25-5-wortliste" aria-label="Permalink to &quot;25.5. Wortliste&quot;">​</a></h2><p>त्यज् 1P त्यजति  verlassen, aufgeben, im Stich lassen</p><blockquote><p>Fut. त्यक्ष्यति<br> Pass. त्यज्यते<br> PPP त्यक्त<br> Inf. त्यक्तुम्<br> Absol. 2: -त्यज्य</p><p>davon:</p><p>त्याग m.: Aufgeben, Verzicht, Meiden</p></blockquote><p>दार m. pl. (!!!): Ehefrau</p><p>द्रव्य n.: Gegenstand, Habe, materieller Besitz, Geld</p><p>धान्य n.:  gedroschenes Getreide</p><p><img src="'+a+'" alt=""><br> Abb.: धान्यम्<br> Khanna<br> [Bildquelle: appaji. -- <a href="http://www.flickr.com/photos/appaji/2205110691/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/appaji/2205110691/</a>. -- Zugriff am 2008-12-15. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung)]</p><p>धृ 1U धरति : halten, festhalten</p><blockquote><p>Fut. धरिष्यति<br> Pass. ध्रियते<br> PPP धृत<br> Inf. धर्तुम्<br> Absol. 2: -धृत्य</p><p>davon:</p><p>धर्म m.: das, was fest ist und fest hält = Dharma</p></blockquote><p>नित्य ३ : ständig, beständig, ewig</p><blockquote><p>नित्यम् Adv.: stets, beständig immer</p></blockquote><p>प्रज्ञा f.:  Weisheit, Erkenntnis</p><p>प्रदान n.: Geben, Spenden ; Gabe, Spende</p><p>मद् 4 P माद्यति (!) : sich freuen, sich an etwas (Instr., Gen., Lok.) berauschen</p><blockquote><p>Fut. मदिष्यति<br> Pass. मद्यते<br> PPP मत्त<br> Inf. मदितुम्</p><p>davon:</p><p>मद m.: Rausch, Sinnenrausch = Sinneslust</p></blockquote><p>मान m.: Einschätzung, Ansehen, Ruhm, Ehre, Stolz, Dünkel, Minderwertigkeitsgefühl ; (man misst sich an anderen)</p><p>यदि Konjunktion: wenn</p><p>न्याय m.: Regel, Prinzip, Methode, Urteil (jurist.), Logik (aus ni + i +a)</p><p>अन्यथा Adv.: anders, sonst, fälschlich, unrichtig</p><p>या 2P याति, यान्ति = गम्</p><blockquote><p>Pass. यायते<br> PPP यात<br> Inf. यातुम्<br> Absol. 2: -याय</p></blockquote><p>दारिद्र्य n. = दरिद्रस्य भावः</p><p>प्रदान n. = दान</p><p>शास् 2P शास्ति, शासति (3. pl.) : befehlen, lehren, bestrafen</p><blockquote><p>Pass. शिष्यते<br> PPP शिष्ट ३ : gelehrt<br> Absol 1.: शासित्वा / शिष्त्वा</p><p>davon:</p><p>शिक्षा f.: Wissenschaft, Unterricht ; Phonetik</p></blockquote><p>स्तेन m.: Dieb</p><p>स्तेय n.: Diebstahl</p><p>किल्बिष n.: Schuld, Beleidigung, Sünde</p><p>विना Postposition: ohne, außer (mit  Akk., Instr., Abl.)</p><p>मूल n.: Wurzel</p><p><img src="'+o+'" alt=""><br> Abb.: मूलानि<br> Varanasi<br> [Bildquelle: oceandesetoiles. -- <a href="http://www.flickr.com/photos/ocean_of_stars/2544053669/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/ocean_of_stars/2544053669/</a>. -- Zugriff am 2008-12-15. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>लिप् 6U लिम्पति (!): bestreichen, beschmieren</p><blockquote><p>Fut. लेप्स्यति<br> Pass. लिप्यते<br> PPP लिप्त<br> Inf. लेप्तुम्</p><p>davon:</p><p>लिप्ति f.: Bestreichen, Schreiben, Schrift</p><p><img src="'+s+'" alt=""><br> Abb.: लिप्तिः<br> Jaina-Manuskript<br> [Bildquelle: Wikipedia, Public domain]</p></blockquote><p>वर्ष n.,m.: Regen, Regenzeit, Jahr</p><p>वह् 1U वहति : führen, fahren, wehen (Wind)</p><blockquote><p>Fut. वक्ष्यति<br> Pass. उह्यते<br> PPP ऊढ<br> Inf. वोढुम्<br> Absol 2: -उह्य</p><p>वह् + वि 1P विवहति : wegführen (nämlich die Braut aus dem Elternhaus) = heiraten</p><p>davon:</p><blockquote><p>विवाह m.: Wegführen, Heirat einer Frau (Instr., saha) (zur Heirat siehe Basham, Wonder S. 166 -171)</p></blockquote></blockquote><p><img src="'+u+'" alt=""><br> Abb.: विवाहः<br> मुंबई<br> [Bildquelle: barnism. -- <a href="http://www.flickr.com/photos/barnism/3079837348/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/barnism/3079837348/</a>. -- Zugriff am 2008-12-15. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnnenung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>नी + वि 1U विनयति : wegführen, unterrichten, erziehen</p><blockquote><p>davon:</p><p>विनय m.: Entfernen, Erziehen, Zucht, buddhist.: Ordensdisziplin, Ordensrecht</p></blockquote><p>विज्ञान n.: Erkenntnis, Kenntnis</p><p>विष्टि f.: Arbeit, Frondienst</p><p><img src="'+p+'" alt=""><br> Abb.: विष्टिः<br> [Bildquelle: Ray Witlin / World Bank. -- <a href="http://www.flickr.com/photos/worldbank/2182943983/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/worldbank/2182943983/</a>. -- Zugriff am 2008-12-15. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnnenung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>वृध् 1Ā वर्धते : wachsen, größer werden</p><blockquote><p>Fut. वर्धिष्यते<br> Pass. वृध्यते<br> PPP वृद्ध : erwachsen, alte, vermehrt<br> Inf. वर्धितुम्</p><p>davon:</p><p>वृद्धि f.: Wachsen, Wachstum, Dehnstufe (aus: vṛdh-ti)</p></blockquote><p>सामर्थ्य n.: das seinem Zweck Entsprechen</p><p>स्वभाव m.: Wesen, Natur, Charakter</p><p>हर्ष m.: (Aufrichten der Körperhärchen), Freude</p><p>हिरण्य ३ : golden ; n.: Gold, Geld, Reichtum</p><p><img src="'+l+'" alt=""><br> Abb.: हिरण्यम्<br> Chennai = சென்னை<br> [Bildquelle: Dilip Muralidaran. -- <a href="http://www.flickr.com/photos/dilipm/2423883232/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/dilipm/2423883232/</a>. -- Zugriff am 2008-12-15. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung)]</p><p>अणु ३ : dünn, fein, dehr klein ; m.: Atom</p><p>गोदान n.: Geben von Kühen / einer Kuh ; zweite Haarschnittzeremonie (ein संस्कार)</p><h2 id="_25-6-ubung" tabindex="-1">25.6. Übung <a class="header-anchor" href="#_25-6-ubung" aria-label="Permalink to &quot;25.6. Übung&quot;">​</a></h2><p>A) Ergänzen Sie die Deklinationsbeispiele von <a href="./lektion16">Lektion 16</a>, Wiederholungsübung A durch Hinzufügen von 4. Dativ (चतुर्थी) und 5. Ablativ (पञ्चमी). Bilden Sie außerdem Deklinationsreihen mit allen bisher gelernten Formen zu</p><p>१. सन्त् (m., n.)</p><p>२. महान्त् (m., n.)</p><p>३. यद् (m., n., f.)</p><p>Lernen Sie diese Deklinationsparadigmen auswendig!</p><p>B) Übersetzen Sie und lösen Sie die Komposita in Sanskrit auf:</p><p>गुर्वादेशाद्रामो ग्रामान्नगरं गत्वा साधुगृहं प्रविश्य साधुमुपस्थायालं क्रोधेनेति वक्ति ॥१॥</p><p>गुरोरधर्मः श्रोतुं न शक्यत इति श्रुत्या च स्मृतिभिश्चोद्यते ॥२॥</p><p>क्षत्रिया जनाञ्छत्रुभ्यो रक्षितुमर्हन्तीति क्षत्रियधर्मः ॥३॥</p><p>कृतयज्ञदोषत्वाद्ब्राह्मणो धनं लब्धुं नार्हति ॥४॥</p><p>धनलाभहेतोस्ते वैश्या व्रतं कृत्वा ब्रह्मचर्यं चरन्ति ॥५॥</p><p>बुद्द्धाश्चार्हन्तश्च दुःखान्मुक्ताः । मुञ्चन्ती बुद्धिर्हि तैः प्राप्ता ॥६॥</p><p>लोभेन च क्रोधेन च मोहेन च जना दुष्यन्ति । ततः प्राप्तकाला नरकं पतन्ति ॥७॥</p><p>क्षत्रियो महानगरतः शत्रुग्रामं योद्धुं शूरयोधानानयति ॥८॥</p><p>पुत्रलाभकारणाद्ब्राह्मणी व्रतं चरति ॥९॥</p><p>लब्धपुत्रत्वाद्द्विजेन महासुखमाप्तम् ॥१०॥</p><p>विष्णुर्भक्तान्मरणात्पाति ॥११॥</p><p>रामाद्विना =  रामं विना = रामेण विना ॥१२॥</p><p>साधोः शिक्षा गुणाय संपद्यते नासाधोः ॥१३॥</p><p>रामः कृष्णाय तिष्ठति ॥१४॥</p><p>सुखेन गच्छति ॥१५॥</p><p>अलं भयेन ॥१६॥</p><p>लोकादधिको हरिः ॥१७॥ (हरि m. = विष्णु / कृष्ण)</p><p><img src="'+d+'" alt=""><br> Abb.: लोकादधिको हरिः<br> श्रीकृष्णः<br> [Bildquelle: Wikipedia, Public domain]</p><h2 id="_25-7-सुभाषितानि" tabindex="-1">25.7. सुभाषितानि <a class="header-anchor" href="#_25-7-सुभाषितानि" aria-label="Permalink to &quot;25.7. सुभाषितानि&quot;">​</a></h2><p>यतो यतो निवर्तते<br> ततस्ततो विमुच्यते ।<br> निवर्तनाद्धि सर्वतो<br> न वेत्ति दुःखमण्वपि ॥१॥</p><blockquote><p>Erklärung: सर्वतस् = sarva &quot;jeder, alle&quot; + -tas ; अणु = Nom., Akk. sg. neutr.</p></blockquote><p>मानाद्वा यदि वा लोभात्<br> क्रोधाद्वा यदि वा भयात् ।<br> यो न्यायमन्यथा ब्रूते<br> स याति नरकं नरः ॥२॥</p><p>भवन्ति नरकाः पापात्<br> पापं दारिद्र्यसंभवम् ।<br> दारिद्र्यमप्रदानेन ॥३॥</p><p>शासनाद्वा विमोक्षाद्वा<br> स्तेनः स्तेयाद्विमुच्यते ।<br> अशासित्वा तु तं राजा<br> स्तेनस्याप्नोति किल्बिषम् ॥मनुस्मृति ८.३१६॥ ॥४॥</p><blockquote><p>Erklärung: राजा = Nom. sg. zu राजन् m. = नृप</p></blockquote><h2 id="_25-8-ubersetzungsubung" tabindex="-1">25.8. Übersetzungsübung <a class="header-anchor" href="#_25-8-ubersetzungsubung" aria-label="Permalink to &quot;25.8. Übersetzungsübung&quot;">​</a></h2><p>1. कौटिलीयार्थशास्त्र १.४.१. über den Nutzen der Ökonomie:</p><p>वार्त्ता धान्यपुशुहिरण्यकुप्यविष्टिप्रदानादौपकारिकी ॥</p><p>2. कौटिलीयार्थशास्त्र १.५. über die Ausbildung eines Fürsten:</p><p>तस्माद्दण्डमूलास्तिस्रो विद्याः ॥१॥ विनयमूलो दण्डः प्राणभृतां योगक्षेमावहः ॥२॥ कृतकः स्वभाविकश्च विनयः ॥३॥ क्रिया हि द्रव्यं विनयति नाद्रव्यम् ॥४॥ शुश्रूषाश्रवणग्रहणविज्ञानोहापोहतत्त्वाभिनिविष्टबुद्धिं विद्या विनयति नेतरम् ॥५॥ ... ॥ वृत्तचौलकर्मा लिपिं संख्यानं चोपयुन्ञ्जीत ॥७॥ वृत्तोपनयस्त्रयीमान्वीक्षिकीं च शिष्टेभ्यो वार्त्तामध्यक्षेभ्यो दण्डनीतिं वक्तृप्रयोक्तृभ्यः ॥८॥ ब्रह्मचर्यं चा षोडशाद्वर्षाद् ॥९॥ अतो गोदानं दारकर्म चास्य ॥१०॥ नित्यश्च विद्यावृद्धसंयोगो विनयवृद्ध्यर्थम्, तन्मूलत्वाद्विनयस्य ॥११॥ ... ॥ श्रुताद्धि प्रज्ञोपजायते प्रज्ञाया योगो योगादात्मवत्तेति विद्यानां सामर्थ्यम् ॥१६॥ ... ॥ विद्याविनयहेतुरिन्द्रियजयः कामक्रोधलोभमानमदहर्षत्यागात्कार्यः ॥१.६.१.॥</p><p>Erklärung der im obigen Text rot hervorgehobenen Wörter:</p><p>1.5.1. तिस्रस् : Nom, Akk, fem. zu त्रि &quot;drei&quot;</p><p>1.5.2. प्राणभृताम् : Gen. pl. m. zu प्राणभृत् m. &quot;Lebewesen&quot;</p><p>1.5.5.  इतरम् Akk. sg. mask. zu इतर ३ &quot;anderer&quot;</p><p>1.5.7. कर्मा : Nom. sg. mask. zu कर्मन् neutr. &quot;Tat, Werk&quot; ; उपयुञ्जीत : OPtativ 3. sg. Ā zu upa-yuj 7 &quot;sich aneignen&quot;: &quot;er möge sich aneignen&quot;</p><p>1.5.8. वक्तृप्रयोक्तृभ्यस् Abl., Dat. pl. zu वक्त्र्प्रयोक्तृ (इतरेतरद्वन्द्व) &quot;Theoretiker und Praktiker&quot;</p><p>1.5.9. षोडश ३ : &quot;sechzehnter&quot;</p><p>1.5.10. कर्म Nom., Akk. sg. zu कर्मन् n. &quot;Tat&quot;</p><p>1.5.16. धि Sandhiform zu हि ; आत्मवत्ता f.: &quot;Selbstbesitz&quot;</p><p>1.6.1. कार्य ३ &quot;zu tuendes, was getan werden muss&quot;</p>',163)])])}const w=n(b,[["render",h]]);export{v as __pageData,w as default};
